use crate::types::{DecideInput, DecideOutput};

const PI: f64 = 3.1415926535;

fn round_to_sigfigs(value: f64, sigfigs: i32) -> f64 {
    if value == 0.0 {
        return 0.0;
    }
    let abs_v = value.abs();
    let exp = abs_v.log10().floor();
    let scale = 10f64.powf((sigfigs as f64) - 1.0 - exp);
    (value * scale).round() / scale
}

fn realcompare(a: f64, b: f64) -> &'static str {
    let ar = round_to_sigfigs(a, 6);
    let br = round_to_sigfigs(b, 6);
    if ar < br {
        "LT"
    } else if ar > br {
        "GT"
    } else {
        "EQ"
    }
}

fn dist2(x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    let dx = x2 - x1;
    let dy = y2 - y1;
    dx * dx + dy * dy
}

fn dist(x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    dist2(x1, y1, x2, y2).sqrt()
}

fn triangle_area(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> f64 {
    ((x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)).abs()) * 0.5
}

fn angle_condition(x1: f64, y1: f64, xv: f64, yv: f64, x3: f64, y3: f64, epsilon: f64) -> bool {
    // Undefined when either ray has zero length.
    if realcompare(x1, xv) == "EQ" && realcompare(y1, yv) == "EQ" {
        return false;
    }
    if realcompare(x3, xv) == "EQ" && realcompare(y3, yv) == "EQ" {
        return false;
    }

    let ux = x1 - xv;
    let uy = y1 - yv;
    let vx = x3 - xv;
    let vy = y3 - yv;

    let un = (ux * ux + uy * uy).sqrt();
    let vn = (vx * vx + vy * vy).sqrt();
    let mut c = (ux * vx + uy * vy) / (un * vn);
    c = c.clamp(-1.0, 1.0);
    let angle = c.acos();

    realcompare(angle, PI - epsilon) == "LT" || realcompare(angle, PI + epsilon) == "GT"
}

fn quadrant(x: f64, y: f64) -> u8 {
    // Priority I, II, III, IV for axis points.
    if realcompare(x, 0.0) != "LT" && realcompare(y, 0.0) != "LT" {
        1
    } else if realcompare(x, 0.0) == "LT" && realcompare(y, 0.0) != "LT" {
        2
    } else if realcompare(x, 0.0) == "LT" && realcompare(y, 0.0) == "LT" {
        3
    } else {
        4
    }
}

fn count_distinct_quadrants(xs: &[f64], ys: &[f64], start: usize, len: usize) -> usize {
    let mut seen = [false; 4];
    for idx in start..(start + len) {
        let q = quadrant(xs[idx], ys[idx]);
        seen[(q - 1) as usize] = true;
    }
    seen.iter().copied().filter(|v| *v).count()
}

fn cannot_fit_circle_radius_r(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64, r: f64) -> bool {
    // Three points fit in/on circle radius r iff all pairwise distances <= 2r.
    // (For obtuse/right triangles, minimal containing circle has diameter longest side;
    // for acute, circumradius is smaller than or equal to half of longest side only when longest <= 2r.)
    let d12 = dist(x1, y1, x2, y2);
    let d13 = dist(x1, y1, x3, y3);
    let d23 = dist(x2, y2, x3, y3);
    let maxd = d12.max(d13).max(d23);
    realcompare(maxd, 2.0 * r) == "GT"
}

fn exists_point_farther_than_line(
    xs: &[f64],
    ys: &[f64],
    start: usize,
    n_pts: usize,
    dist_limit: f64,
) -> bool {
    let i = start;
    let j = start + n_pts - 1;
    let x1 = xs[i];
    let y1 = ys[i];
    let x2 = xs[j];
    let y2 = ys[j];

    if realcompare(x1, x2) == "EQ" && realcompare(y1, y2) == "EQ" {
        for k in (i + 1)..j {
            let d = dist(xs[k], ys[k], x1, y1);
            if realcompare(d, dist_limit) == "GT" {
                return true;
            }
        }
        return false;
    }

    let dx = x2 - x1;
    let dy = y2 - y1;
    let denom = (dx * dx + dy * dy).sqrt();

    for k in (i + 1)..j {
        let num = (dy * xs[k] - dx * ys[k] + x2 * y1 - y2 * x1).abs();
        let d = num / denom;
        if realcompare(d, dist_limit) == "GT" {
            return true;
        }
    }
    false
}

pub fn decide(input: &DecideInput) -> DecideOutput {
    let n = input.numpoints;
    let p = &input.parameters;
    let xs = &input.x;
    let ys = &input.y;

    let mut cmv = vec![false; 15];

    // LIC 1
    for i in 0..(n - 1) {
        if realcompare(dist(xs[i], ys[i], xs[i + 1], ys[i + 1]), p.length1) == "GT" {
            cmv[0] = true;
            break;
        }
    }

    // LIC 2
    if n >= 3 {
        for i in 0..(n - 2) {
            if cannot_fit_circle_radius_r(xs[i], ys[i], xs[i + 1], ys[i + 1], xs[i + 2], ys[i + 2], p.radius1) {
                cmv[1] = true;
                break;
            }
        }
    }

    // LIC 3
    if n >= 3 {
        for i in 0..(n - 2) {
            if angle_condition(xs[i], ys[i], xs[i + 1], ys[i + 1], xs[i + 2], ys[i + 2], p.epsilon) {
                cmv[2] = true;
                break;
            }
        }
    }

    // LIC 4
    if n >= 3 {
        for i in 0..(n - 2) {
            if realcompare(
                triangle_area(xs[i], ys[i], xs[i + 1], ys[i + 1], xs[i + 2], ys[i + 2]),
                p.area1,
            ) == "GT"
            {
                cmv[3] = true;
                break;
            }
        }
    }

    // LIC 5
    for i in 0..=(n - p.q_pts) {
        let qcount = count_distinct_quadrants(xs, ys, i, p.q_pts);
        if qcount > p.quads {
            cmv[4] = true;
            break;
        }
    }

    // LIC 6
    for i in 0..(n - 1) {
        if realcompare(xs[i + 1] - xs[i], 0.0) == "LT" {
            cmv[5] = true;
            break;
        }
    }

    // LIC 7
    if n >= 3 {
        for i in 0..=(n - p.n_pts) {
            if exists_point_farther_than_line(xs, ys, i, p.n_pts, p.dist) {
                cmv[6] = true;
                break;
            }
        }
    }

    // LIC 8
    if n >= 3 {
        let sep = p.k_pts + 1;
        for i in 0..(n - sep) {
            if realcompare(dist(xs[i], ys[i], xs[i + sep], ys[i + sep]), p.length1) == "GT" {
                cmv[7] = true;
                break;
            }
        }
    }

    // LIC 9
    if n >= 5 {
        let joff = p.a_pts + 1;
        let koff = p.b_pts + 1;
        for i in 0..n {
            let j = i + joff;
            let k = j + koff;
            if k >= n {
                break;
            }
            if cannot_fit_circle_radius_r(xs[i], ys[i], xs[j], ys[j], xs[k], ys[k], p.radius1) {
                cmv[8] = true;
                break;
            }
        }
    }

    // LIC 10
    if n >= 5 {
        let joff = p.c_pts + 1;
        let koff = p.d_pts + 1;
        for i in 0..n {
            let j = i + joff;
            let k = j + koff;
            if k >= n {
                break;
            }
            if angle_condition(xs[i], ys[i], xs[j], ys[j], xs[k], ys[k], p.epsilon) {
                cmv[9] = true;
                break;
            }
        }
    }

    // LIC 11
    if n >= 5 {
        let joff = p.e_pts + 1;
        let koff = p.f_pts + 1;
        for i in 0..n {
            let j = i + joff;
            let k = j + koff;
            if k >= n {
                break;
            }
            if realcompare(triangle_area(xs[i], ys[i], xs[j], ys[j], xs[k], ys[k]), p.area1) == "GT" {
                cmv[10] = true;
                break;
            }
        }
    }

    // LIC 12
    if n >= 3 {
        let sep = p.g_pts + 1;
        for i in 0..(n - sep) {
            if realcompare(xs[i + sep] - xs[i], 0.0) == "LT" {
                cmv[11] = true;
                break;
            }
        }
    }

    // LIC 13
    if n >= 3 {
        let sep = p.k_pts + 1;
        let mut found_gt_length1 = false;
        let mut found_lt_length2 = false;
        for i in 0..(n - sep) {
            let d = dist(xs[i], ys[i], xs[i + sep], ys[i + sep]);
            if realcompare(d, p.length1) == "GT" {
                found_gt_length1 = true;
            }
            if realcompare(d, p.length2) == "LT" {
                found_lt_length2 = true;
            }
            if found_gt_length1 && found_lt_length2 {
                cmv[12] = true;
                break;
            }
        }
    }

    // LIC 14
    if n >= 5 {
        let joff = p.a_pts + 1;
        let koff = p.b_pts + 1;
        let mut found_not_in_radius1 = false;
        let mut found_in_radius2 = false;
        for i in 0..n {
            let j = i + joff;
            let k = j + koff;
            if k >= n {
                break;
            }
            let c1 = cannot_fit_circle_radius_r(xs[i], ys[i], xs[j], ys[j], xs[k], ys[k], p.radius1);
            if c1 {
                found_not_in_radius1 = true;
            }
            let c2 = !cannot_fit_circle_radius_r(xs[i], ys[i], xs[j], ys[j], xs[k], ys[k], p.radius2);
            if c2 {
                found_in_radius2 = true;
            }
            if found_not_in_radius1 && found_in_radius2 {
                cmv[13] = true;
                break;
            }
        }
    }

    // LIC 15
    if n >= 5 {
        let joff = p.e_pts + 1;
        let koff = p.f_pts + 1;
        let mut found_gt_area1 = false;
        let mut found_lt_area2 = false;
        for i in 0..n {
            let j = i + joff;
            let k = j + koff;
            if k >= n {
                break;
            }
            let area = triangle_area(xs[i], ys[i], xs[j], ys[j], xs[k], ys[k]);
            if realcompare(area, p.area1) == "GT" {
                found_gt_area1 = true;
            }
            if realcompare(area, p.area2) == "LT" {
                found_lt_area2 = true;
            }
            if found_gt_area1 && found_lt_area2 {
                cmv[14] = true;
                break;
            }
        }
    }

    let mut pum = vec![vec![false; 15]; 15];
    for i in 0..15 {
        for j in 0..15 {
            if i == j {
                pum[i][j] = input.pum_diag[i];
            } else {
                let connector = input.lcm[i][j].as_str();
                pum[i][j] = match connector {
                    "NOTUSED" => true,
                    "ANDD" => cmv[i] && cmv[j],
                    "ORR" => cmv[i] || cmv[j],
                    _ => false,
                };
            }
        }
    }

    let mut fuv = vec![false; 15];
    for i in 0..15 {
        if !pum[i][i] {
            fuv[i] = true;
        } else {
            fuv[i] = pum[i].iter().all(|v| *v);
        }
    }

    let launch = fuv.iter().all(|v| *v);

    DecideOutput {
        cmv,
        pum,
        fuv,
        launch,
    }
}
